// SAT R&W Batch 8 - Expression & Rhetoric II (120 questions)
export const rwBatch8 = [
  { id: 'sat_rw_b8_001', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The city recently built a new park downtown. ________, local residents have more green space for exercise and relaxation.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'As a result' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'Meanwhile' }], correct: 'A', explanation: '"As a result" signals the effect (more green space) caused by the new park.' },
  { id: 'sat_rw_b8_002', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The bakery uses organic flour. ________, it sources its eggs from local farms.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Additionally' }, { letter: 'B', text: 'Nevertheless' }, { letter: 'C', text: 'On the other hand' }, { letter: 'D', text: 'Consequently' }], correct: 'A', explanation: '"Additionally" adds a second similar practice (local eggs) to the first (organic flour).' },
  { id: 'sat_rw_b8_003', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'Solar panels require a large upfront investment. ________, the long-term savings on electricity bills make them worthwhile.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'However' }, { letter: 'B', text: 'Therefore' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'For instance' }], correct: 'A', explanation: '"However" introduces a contrast between the cost and the long-term benefit.' },
  { id: 'sat_rw_b8_004', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The temperature dropped below freezing overnight. ________, the roads were covered in ice by morning.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Consequently' }, { letter: 'B', text: 'Meanwhile' }, { letter: 'C', text: 'In addition' }, { letter: 'D', text: 'By contrast' }], correct: 'A', explanation: '"Consequently" shows that the icy roads were a direct result of the freezing temperature.' },
  { id: 'sat_rw_b8_005', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The museum offers free admission on Sundays. ________, it hosts educational workshops for children every Saturday.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Moreover' }, { letter: 'B', text: 'Instead' }, { letter: 'C', text: 'Otherwise' }, { letter: 'D', text: 'Regardless' }], correct: 'A', explanation: '"Moreover" adds another community benefit offered by the museum.' },
  { id: 'sat_rw_b8_006', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The dog was tired. The dog lay down under the tree.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'Tired, the dog lay down under the tree.' }, { letter: 'B', text: 'The dog was tired, the dog lay down under the tree.' }, { letter: 'C', text: 'The dog was tired and the dog lay down under the tree.' }, { letter: 'D', text: 'Being that the dog was tired, laying down under the tree.' }], correct: 'A', explanation: 'Option A concisely combines the ideas using a participial adjective.' },
  { id: 'sat_rw_b8_007', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The restaurant changed its menu to include healthier options. ________, it replaced sugary sodas with fresh-squeezed juices.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'For example' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'On the contrary' }, { letter: 'D', text: 'Meanwhile' }], correct: 'A', explanation: '"For example" introduces a specific instance of the healthier menu changes.' },
  { id: 'sat_rw_b8_008', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The politician\'s speech was filled with ________ language, using simple words that anyone could understand rather than technical jargon.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'accessible' }, { letter: 'B', text: 'obscure' }, { letter: 'C', text: 'elaborate' }, { letter: 'D', text: 'ambiguous' }], correct: 'A', explanation: '"Accessible" means easy to understand, matching the context clue about simple words.' },
  { id: 'sat_rw_b8_009', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The new library was designed to be environmentally friendly. ________, it was built with recycled materials and powered by solar energy.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Specifically' }, { letter: 'B', text: 'Conversely' }, { letter: 'C', text: 'Nonetheless' }, { letter: 'D', text: 'Alternatively' }], correct: 'A', explanation: '"Specifically" introduces detailed examples of the eco-friendly design.' },
  { id: 'sat_rw_b8_010', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The orchestra ________ its final concert of the season next Friday.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'performs' }, { letter: 'B', text: 'perform' }, { letter: 'C', text: 'performing' }, { letter: 'D', text: 'have performed' }], correct: 'A', explanation: '"Orchestra" is a singular collective noun requiring the singular verb "performs."' },
  { id: 'sat_rw_b8_011', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'Many students struggle with time management in college. ________, learning to prioritize tasks early can lead to academic success.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Therefore' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'Meanwhile' }], correct: 'A', explanation: '"Therefore" logically connects the problem (time management struggles) with the recommended solution.' },
  { id: 'sat_rw_b8_012', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'Although the critic praised the film\'s visual effects, she found the plot to be ________, lacking any surprising twists or original ideas.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'predictable' }, { letter: 'B', text: 'riveting' }, { letter: 'C', text: 'innovative' }, { letter: 'D', text: 'compelling' }], correct: 'A', explanation: '"Predictable" matches the clue about lacking surprises and originality.' },
  { id: 'sat_rw_b8_013', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The rain was heavy. We decided to cancel the picnic.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'Because the rain was heavy, we decided to cancel the picnic.' }, { letter: 'B', text: 'The rain was heavy, we decided to cancel the picnic.' }, { letter: 'C', text: 'The rain being heavy and canceling the picnic.' }, { letter: 'D', text: 'Heavy rain, so the picnic was canceled by us.' }], correct: 'A', explanation: '"Because" clearly establishes the cause-and-effect relationship.' },
  { id: 'sat_rw_b8_014', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The school board voted to extend the school year by five days. ________, many parents expressed concern about disrupted summer plans.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'In response' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'For example' }, { letter: 'D', text: 'Furthermore' }], correct: 'A', explanation: '"In response" shows that the parents\' concern was a reaction to the school board\'s decision.' },
  { id: 'sat_rw_b8_015', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The professor asked each student to submit ________ essay by Friday.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'his or her' }, { letter: 'B', text: 'they\'re' }, { letter: 'C', text: 'its' }, { letter: 'D', text: 'there' }], correct: 'A', explanation: '"Each student" is singular, so "his or her" provides correct pronoun agreement.' },
  { id: 'sat_rw_b8_016', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Honeybees communicate the location of food sources through a series of movements known as the waggle dance. By varying the angle and duration of their dance, bees can convey both the direction and distance of flowers relative to the hive.', question: 'What is the main idea of this passage?', options: [{ letter: 'A', text: 'Honeybees use a specific dance to share information about food locations with other bees.' }, { letter: 'B', text: 'Honeybees are the most intelligent insects in the animal kingdom.' }, { letter: 'C', text: 'The waggle dance is performed only by queen bees.' }, { letter: 'D', text: 'Bees prefer flowers that are close to the hive.' }], correct: 'A', explanation: 'The passage describes how the waggle dance communicates food source locations.' },
  { id: 'sat_rw_b8_017', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The hiking trail was steep and rocky. ________, many beginners found it difficult to complete.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'As a result' }, { letter: 'B', text: 'On the other hand' }, { letter: 'C', text: 'In addition' }, { letter: 'D', text: 'By contrast' }], correct: 'A', explanation: '"As a result" connects the trail\'s difficulty to beginners\' struggles.' },
  { id: 'sat_rw_b8_018', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The company offers competitive salaries. ________, employees receive generous health benefits and retirement plans.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'In addition' }, { letter: 'B', text: 'Nevertheless' }, { letter: 'C', text: 'Instead' }, { letter: 'D', text: 'Conversely' }], correct: 'A', explanation: '"In addition" introduces additional benefits beyond the salaries.' },
  { id: 'sat_rw_b8_019', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The scientist was known for her ________ approach to research, carefully testing each hypothesis multiple times before drawing any conclusions.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'meticulous' }, { letter: 'B', text: 'reckless' }, { letter: 'C', text: 'hasty' }, { letter: 'D', text: 'superficial' }], correct: 'A', explanation: '"Meticulous" means extremely careful, matching the description of repeated testing.' },
  { id: 'sat_rw_b8_020', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'Running is a popular form of exercise. ________, it requires no special equipment beyond a good pair of shoes.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'After all' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Nevertheless' }, { letter: 'D', text: 'On the contrary' }], correct: 'A', explanation: '"After all" provides supporting reasoning for why running is popular.' },
  { id: 'sat_rw_b8_021', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The concert was loud. It was also exciting.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'The concert was both loud and exciting.' }, { letter: 'B', text: 'The concert was loud, it was also exciting.' }, { letter: 'C', text: 'Loud and being exciting, the concert was.' }, { letter: 'D', text: 'The concert was loud and it was exciting too.' }], correct: 'A', explanation: '"Both...and" creates a parallel, concise structure.' },
  { id: 'sat_rw_b8_022', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The collection of rare stamps ________ displayed in the museum\'s main gallery.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: 'The subject is "collection" (singular), not "stamps," so "is" is correct.' },
  { id: 'sat_rw_b8_023', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'easy', passage: 'A travel magazine article begins: "Imagine waking up to the sound of waves gently crashing against white sand beaches, the scent of tropical flowers filling the warm morning air."', question: 'The author most likely uses this opening to:', options: [{ letter: 'A', text: 'appeal to the reader\'s senses to create a desire to visit the destination' }, { letter: 'B', text: 'provide factual data about beach erosion patterns' }, { letter: 'C', text: 'warn travelers about potential dangers at the beach' }, { letter: 'D', text: 'compare different vacation destinations objectively' }], correct: 'A', explanation: 'The vivid sensory details are designed to make readers imagine and desire the experience.' },
  { id: 'sat_rw_b8_024', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'Regular exercise improves cardiovascular health. ________, it has been shown to reduce symptoms of anxiety and depression.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Furthermore' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'Instead' }, { letter: 'D', text: 'On the contrary' }], correct: 'A', explanation: '"Furthermore" adds a second benefit (mental health) to the first (cardiovascular health).' },
  { id: 'sat_rw_b8_025', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The road was closed due to construction. ________, drivers were advised to take the highway detour.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Therefore' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'Moreover' }, { letter: 'D', text: 'Incidentally' }], correct: 'A', explanation: '"Therefore" signals that the detour advice is a logical result of the road closure.' },
  { id: 'sat_rw_b8_026', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'Despite the team\'s ________ start to the season, losing five of their first six games, they rallied to finish with a winning record.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'dismal' }, { letter: 'B', text: 'triumphant' }, { letter: 'C', text: 'promising' }, { letter: 'D', text: 'stellar' }], correct: 'A', explanation: '"Dismal" means dreadful, matching the context of losing five of six games.' },
  { id: 'sat_rw_b8_027', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The store was running a massive sale. ________, the parking lot was completely full by ten in the morning.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Not surprisingly' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Alternatively' }, { letter: 'D', text: 'Meanwhile' }], correct: 'A', explanation: '"Not surprisingly" indicates the full parking lot was an expected result of the sale.' },
  { id: 'sat_rw_b8_028', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'The coach told the players to stretch ________ muscles before the game.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'their' }, { letter: 'B', text: 'there' }, { letter: 'C', text: 'they\'re' }, { letter: 'D', text: 'its' }], correct: 'A', explanation: '"Their" is the possessive pronoun referring to the plural "players."' },
  { id: 'sat_rw_b8_029', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The garden needed water. The flowers were wilting in the heat.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'The garden needed water because the flowers were wilting in the heat.' }, { letter: 'B', text: 'The garden needed water, the flowers were wilting in the heat.' }, { letter: 'C', text: 'Needing water and wilting in the heat.' }, { letter: 'D', text: 'The garden needed water also the flowers were wilting.' }], correct: 'A', explanation: '"Because" correctly establishes the causal relationship between wilting and the need for water.' },
  { id: 'sat_rw_b8_030', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'The Great Wall of China was not built all at once. Various dynasties constructed different sections over a period spanning more than two thousand years. The earliest walls were built as early as the seventh century BCE, and construction continued until the seventeenth century CE.', question: 'Based on the passage, which statement is accurate?', options: [{ letter: 'A', text: 'The Great Wall was built in stages by different ruling groups over many centuries.' }, { letter: 'B', text: 'A single emperor ordered the construction of the entire Great Wall.' }, { letter: 'C', text: 'The Great Wall took exactly two thousand years to complete.' }, { letter: 'D', text: 'Construction of the Great Wall began in the seventeenth century.' }], correct: 'A', explanation: 'The passage states various dynasties built different sections over more than two thousand years.' },
  { id: 'sat_rw_b8_031', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'Cats are popular pets because they are independent. ________, dogs are often preferred by people who want a more social companion.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'By contrast' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'Consequently' }, { letter: 'D', text: 'Moreover' }], correct: 'A', explanation: '"By contrast" highlights the difference between cats\' independence and dogs\' social nature.' },
  { id: 'sat_rw_b8_032', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The experiment had to be conducted under strict conditions. ________, any contamination could invalidate the results.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Otherwise' }, { letter: 'B', text: 'Likewise' }, { letter: 'C', text: 'Accordingly' }, { letter: 'D', text: 'In summary' }], correct: 'A', explanation: '"Otherwise" warns of the negative consequence of not maintaining strict conditions.' },
  { id: 'sat_rw_b8_033', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The negotiations between the two countries were ________, with both sides making significant compromises to reach an agreement.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'productive' }, { letter: 'B', text: 'futile' }, { letter: 'C', text: 'hostile' }, { letter: 'D', text: 'stagnant' }], correct: 'A', explanation: '"Productive" means yielding good results, matching the context of significant compromises and agreement.' },
  { id: 'sat_rw_b8_034', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The student forgot to set an alarm. ________, she overslept and missed her first class.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'As a result' }, { letter: 'B', text: 'Furthermore' }, { letter: 'C', text: 'In other words' }, { letter: 'D', text: 'Nevertheless' }], correct: 'A', explanation: '"As a result" shows that oversleeping was the consequence of not setting an alarm.' },
  { id: 'sat_rw_b8_035', category: 'writing', subcategory: 'grammar', difficulty: 'easy', passage: 'Neither the teacher nor the students ________ aware of the schedule change.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'were' }, { letter: 'B', text: 'was' }, { letter: 'C', text: 'is' }, { letter: 'D', text: 'has been' }], correct: 'A', explanation: 'With "neither...nor," the verb agrees with the nearer subject "students" (plural), so "were" is correct.' },
  { id: 'sat_rw_b8_036', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'The old bridge was deemed unsafe. ________, the city allocated funds for a replacement.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Accordingly' }, { letter: 'B', text: 'Meanwhile' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'Surprisingly' }], correct: 'A', explanation: '"Accordingly" indicates that funding followed logically from the safety concern.' },
  { id: 'sat_rw_b8_037', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'easy', passage: 'An advertisement reads: "Nine out of ten dentists recommend BrightSmile toothpaste for healthier gums and stronger enamel."', question: 'The advertisement primarily uses which persuasive technique?', options: [{ letter: 'A', text: 'Appeal to authority by citing expert endorsement' }, { letter: 'B', text: 'Emotional appeal through storytelling' }, { letter: 'C', text: 'Logical reasoning based on scientific data' }, { letter: 'D', text: 'Bandwagon appeal by emphasizing popularity' }], correct: 'A', explanation: 'Citing dentists\' recommendations is an appeal to professional authority.' },
  { id: 'sat_rw_b8_038', category: 'writing', subcategory: 'sentence-structure', difficulty: 'easy', passage: 'The presentation was informative. It was also well-organized.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'The presentation was both informative and well-organized.' }, { letter: 'B', text: 'The presentation was informative, it was also well-organized.' }, { letter: 'C', text: 'Informative and being well-organized, the presentation was.' }, { letter: 'D', text: 'The presentation was informative plus well-organized also.' }], correct: 'A', explanation: '"Both...and" creates a concise parallel structure combining both qualities.' },
  { id: 'sat_rw_b8_039', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'easy', passage: 'Elephants are highly social animals. ________, they live in groups led by the oldest female, called the matriarch.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'In fact' }, { letter: 'B', text: 'Nevertheless' }, { letter: 'C', text: 'On the contrary' }, { letter: 'D', text: 'Instead' }], correct: 'A', explanation: '"In fact" reinforces the claim about elephants being social with a supporting detail.' },
  { id: 'sat_rw_b8_040', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'The octopus is widely regarded as the most intelligent invertebrate. It can solve puzzles, open jars, and even use tools. Some researchers believe octopuses can recognize individual human faces, a skill previously thought to be limited to vertebrates.', question: 'The passage primarily serves to:', options: [{ letter: 'A', text: 'illustrate the remarkable cognitive abilities of octopuses' }, { letter: 'B', text: 'argue that octopuses should be classified as vertebrates' }, { letter: 'C', text: 'compare octopuses to other marine invertebrates' }, { letter: 'D', text: 'explain how octopuses evolved their intelligence' }], correct: 'A', explanation: 'The passage presents examples of octopus intelligence such as puzzle-solving and facial recognition.' },
  { id: 'sat_rw_b8_041', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The city council proposed raising property taxes to fund road repairs. Critics argued that the tax increase would burden low-income homeowners. ________, supporters maintained that failing to repair roads would cost taxpayers even more in vehicle damage claims.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'On the other hand' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'For instance' }, { letter: 'D', text: 'In addition' }], correct: 'A', explanation: '"On the other hand" introduces the supporters\' counterargument to the critics\' concern.' },
  { id: 'sat_rw_b8_042', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'medium', passage: 'In a speech to graduating seniors, the principal said: "When I stood where you stand twenty years ago, I had no idea what the future held. But I knew one thing: the friends I made here and the lessons I learned would carry me through whatever challenges lay ahead."', question: 'The principal most likely shares this personal anecdote to:', options: [{ letter: 'A', text: 'build a connection with the audience by showing shared experience' }, { letter: 'B', text: 'boast about personal accomplishments over the past twenty years' }, { letter: 'C', text: 'criticize the current education system\'s shortcomings' }, { letter: 'D', text: 'discourage students from worrying about their grades' }], correct: 'A', explanation: 'Sharing a personal story of being in the graduates\' position builds rapport and relatability.' },
  { id: 'sat_rw_b8_043', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'Early astronomers believed Earth was the center of the universe. ________, advances in telescopic observation revealed that Earth orbits the Sun, fundamentally changing our understanding of the cosmos.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Eventually' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'For example' }, { letter: 'D', text: 'In addition' }], correct: 'A', explanation: '"Eventually" signals a shift in understanding that occurred over time.' },
  { id: 'sat_rw_b8_044', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The data from the survey ________ that most respondents prefer working from home at least two days per week.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'indicate' }, { letter: 'B', text: 'indicates' }, { letter: 'C', text: 'is indicating' }, { letter: 'D', text: 'has indicated' }], correct: 'A', explanation: '"Data" is plural, so the plural verb "indicate" is correct.' },
  { id: 'sat_rw_b8_045', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The company invested heavily in employee training programs. ________, worker productivity increased by fifteen percent within the first year.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'As a result' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Meanwhile' }, { letter: 'D', text: 'On the contrary' }], correct: 'A', explanation: '"As a result" connects the investment in training to the measurable increase in productivity.' },
  { id: 'sat_rw_b8_046', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The professor\'s lectures were so ________ that students often lost track of time, fully absorbed in the material she presented.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'engrossing' }, { letter: 'B', text: 'tedious' }, { letter: 'C', text: 'superficial' }, { letter: 'D', text: 'confounding' }], correct: 'A', explanation: '"Engrossing" means completely absorbing one\'s attention, matching the clue about students losing track of time.' },
  { id: 'sat_rw_b8_047', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'Researchers found that plants grow faster when exposed to classical music. ________, the mechanism behind this phenomenon remains unclear, and some scientists question whether the results can be replicated.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Nevertheless' }, { letter: 'B', text: 'Therefore' }, { letter: 'C', text: 'Moreover' }, { letter: 'D', text: 'Similarly' }], correct: 'A', explanation: '"Nevertheless" introduces a qualification that tempers the initial finding with scientific skepticism.' },
  { id: 'sat_rw_b8_048', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The architect designed the building. The building won several awards. The awards were for sustainability.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'The building designed by the architect won several sustainability awards.' }, { letter: 'B', text: 'The architect designed the building and it won several awards and they were for sustainability.' }, { letter: 'C', text: 'Several awards for sustainability were won by the building the architect designed it.' }, { letter: 'D', text: 'The architect designed the building, it won awards, sustainability ones.' }], correct: 'A', explanation: 'Option A efficiently combines all three ideas into a single clear sentence.' },
  { id: 'sat_rw_b8_049', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'medium', passage: 'A nonprofit organization\'s fundraising letter states: "For just fifty cents a day—less than the cost of a cup of coffee—you can provide clean drinking water to a child in need. Last year, donors like you helped us reach over 100,000 families."', question: 'Which rhetorical strategies does the letter primarily employ?', options: [{ letter: 'A', text: 'Minimizing the perceived cost and citing past success to encourage donations' }, { letter: 'B', text: 'Using fear to pressure readers into donating immediately' }, { letter: 'C', text: 'Presenting complex scientific data about water contamination' }, { letter: 'D', text: 'Comparing the organization\'s work to that of competitors' }], correct: 'A', explanation: 'The letter makes the cost seem small (less than coffee) and proves impact through past results.' },
  { id: 'sat_rw_b8_050', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The novel received widespread critical acclaim. ________, it struggled to find a large readership, selling fewer than ten thousand copies in its first year.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Despite this' }, { letter: 'B', text: 'As a result' }, { letter: 'C', text: 'Likewise' }, { letter: 'D', text: 'Therefore' }], correct: 'A', explanation: '"Despite this" contrasts the positive reviews with the disappointing sales figures.' },
  { id: 'sat_rw_b8_051', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'If the committee ________ to approve the proposal by next week, the project will be delayed until the following quarter.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'fails' }, { letter: 'B', text: 'fail' }, { letter: 'C', text: 'failing' }, { letter: 'D', text: 'have failed' }], correct: 'A', explanation: '"Committee" is singular, so "fails" is correct in this conditional sentence.' },
  { id: 'sat_rw_b8_052', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'Wind energy is renewable and produces no greenhouse gas emissions during operation. ________, wind turbines can be noisy and may pose a threat to bird populations.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'However' }, { letter: 'B', text: 'Therefore' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'In fact' }], correct: 'A', explanation: '"However" introduces drawbacks that contrast with the stated benefits of wind energy.' },
  { id: 'sat_rw_b8_053', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'During the Industrial Revolution, factory owners often employed children as young as five. These children worked long hours in dangerous conditions for meager wages. It was not until the passage of the Factory Acts in the mid-nineteenth century that child labor began to be regulated in Britain.', question: 'It can be inferred from the passage that before the Factory Acts:', options: [{ letter: 'A', text: 'there were few legal protections for child workers in Britain' }, { letter: 'B', text: 'children preferred factory work to attending school' }, { letter: 'C', text: 'factory owners were required to educate their workers' }, { letter: 'D', text: 'child labor was limited to agricultural work' }], correct: 'A', explanation: 'The passage states regulation began with the Factory Acts, implying little protection existed before.' },
  { id: 'sat_rw_b8_054', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The mayor promised to reduce crime rates within six months of taking office. ________, crime statistics showed a fifteen percent decrease in the first quarter alone.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Indeed' }, { letter: 'B', text: 'Conversely' }, { letter: 'C', text: 'Regardless' }, { letter: 'D', text: 'Alternatively' }], correct: 'A', explanation: '"Indeed" confirms that the mayor\'s promise was supported by actual results.' },
  { id: 'sat_rw_b8_055', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The research team hypothesized that caffeine improves short-term memory. To test this, they conducted a double-blind study with two hundred participants. ________, they divided participants into a caffeine group and a placebo group.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'First' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'In conclusion' }, { letter: 'D', text: 'Nevertheless' }], correct: 'A', explanation: '"First" introduces the initial step in the experimental procedure.' },
  { id: 'sat_rw_b8_056', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The CEO\'s decision to close the overseas factory was ________, drawing sharp criticism from labor unions and praise from environmental groups simultaneously.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'controversial' }, { letter: 'B', text: 'unanimous' }, { letter: 'C', text: 'trivial' }, { letter: 'D', text: 'inconsequential' }], correct: 'A', explanation: '"Controversial" means causing disagreement, matching the mixed reactions described.' },
  { id: 'sat_rw_b8_057', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The documentary examines the environmental impact of fast fashion. ________, it profiles workers in overseas garment factories who earn less than two dollars per hour.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'In addition' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'Consequently' }], correct: 'A', explanation: '"In addition" introduces a second topic the documentary covers alongside environmental impact.' },
  { id: 'sat_rw_b8_058', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The singer, along with her band members, ________ scheduled to perform at the festival next weekend.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'is' }, { letter: 'B', text: 'are' }, { letter: 'C', text: 'were' }, { letter: 'D', text: 'have been' }], correct: 'A', explanation: 'The subject is "singer" (singular). "Along with her band members" is a parenthetical phrase that does not change the subject.' },
  { id: 'sat_rw_b8_059', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'Ancient Romans built an extensive network of roads that connected their vast empire. These roads facilitated trade, enabled rapid military movement, and promoted cultural exchange. ________, many Roman roads are still in use today, a testament to their remarkable engineering.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Remarkably' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'As a result' }, { letter: 'D', text: 'Meanwhile' }], correct: 'A', explanation: '"Remarkably" emphasizes the surprising durability of roads built thousands of years ago.' },
  { id: 'sat_rw_b8_060', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'medium', passage: 'In a persuasive essay, a student writes: "Schools that have implemented later start times report fewer student absences, higher test scores, and lower rates of depression among teenagers. Given this overwhelming evidence, it is irresponsible for school boards to continue forcing students to begin classes before 8:00 AM."', question: 'The student\'s argument primarily relies on:', options: [{ letter: 'A', text: 'presenting data-supported benefits and using strong language to urge action' }, { letter: 'B', text: 'quoting educational experts and psychologists by name' }, { letter: 'C', text: 'sharing a personal narrative about sleep deprivation' }, { letter: 'D', text: 'comparing American schools to those in other countries' }], correct: 'A', explanation: 'The student cites measurable outcomes (absences, scores, depression) and uses forceful words like "irresponsible."' },
  { id: 'sat_rw_b8_061', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The new medication showed promising results in early trials, significantly reducing symptoms in eighty percent of patients. ________, the sample size was small, and larger studies are needed before the drug can be approved for widespread use.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'That said' }, { letter: 'B', text: 'Furthermore' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'In other words' }], correct: 'A', explanation: '"That said" introduces a qualification that tempers the initially positive results.' },
  { id: 'sat_rw_b8_062', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The chef prepared the meal using only locally sourced ingredients. She wanted to support nearby farmers. She also wanted to reduce the restaurant\'s carbon footprint.', question: 'Which choice best combines these sentences?', options: [{ letter: 'A', text: 'To support nearby farmers and reduce the restaurant\'s carbon footprint, the chef prepared the meal using only locally sourced ingredients.' }, { letter: 'B', text: 'The chef prepared the meal using locally sourced ingredients, she wanted to support farmers, and she wanted to reduce carbon footprint.' }, { letter: 'C', text: 'The chef wanted to support nearby farmers also reducing carbon footprint by preparing locally sourced meals.' }, { letter: 'D', text: 'Using locally sourced ingredients and the chef supported farmers and reduced carbon footprint in the meal.' }], correct: 'A', explanation: 'Option A concisely states both motivations before the main action.' },
  { id: 'sat_rw_b8_063', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The manager\'s ________ leadership style, which involved soliciting input from every team member before making decisions, fostered a strong sense of inclusion in the workplace.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'collaborative' }, { letter: 'B', text: 'autocratic' }, { letter: 'C', text: 'detached' }, { letter: 'D', text: 'impulsive' }], correct: 'A', explanation: '"Collaborative" means involving cooperation, matching the description of soliciting input from team members.' },
  { id: 'sat_rw_b8_064', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The volcano had been dormant for over three hundred years. ________, when seismologists detected increased activity beneath its surface, local authorities quickly implemented evacuation plans.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Thus' }, { letter: 'B', text: 'In addition' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'On the contrary' }], correct: 'A', explanation: '"Thus" connects the rare and alarming seismic activity to the logical decision to evacuate.' },
  { id: 'sat_rw_b8_065', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The museum, renowned for ________ collection of Impressionist paintings, attracts over a million visitors annually.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'its' }, { letter: 'B', text: 'it\'s' }, { letter: 'C', text: 'their' }, { letter: 'D', text: 'they\'re' }], correct: 'A', explanation: '"Its" is the possessive form of "it," referring to the museum.' },
  { id: 'sat_rw_b8_066', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'Public transportation reduces traffic congestion in urban areas. ________, it lowers per-capita carbon emissions by decreasing the number of individual cars on the road.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Moreover' }, { letter: 'B', text: 'Conversely' }, { letter: 'C', text: 'Instead' }, { letter: 'D', text: 'Regardless' }], correct: 'A', explanation: '"Moreover" adds an additional environmental benefit beyond congestion reduction.' },
  { id: 'sat_rw_b8_067', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The introduction of the printing press in the fifteenth century dramatically lowered the cost of producing books. Before its invention, books were copied by hand, a slow and expensive process that limited literacy to the wealthy and the clergy. Within decades of Gutenberg\'s innovation, books became affordable for a broader segment of society.', question: 'According to the passage, the printing press was significant primarily because it:', options: [{ letter: 'A', text: 'made books more accessible to people beyond the upper classes' }, { letter: 'B', text: 'eliminated the need for handwriting entirely' }, { letter: 'C', text: 'was invented by a member of the clergy' }, { letter: 'D', text: 'reduced the quality of book production' }], correct: 'A', explanation: 'The passage emphasizes that books became affordable for a broader segment of society.' },
  { id: 'sat_rw_b8_068', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'Many historians consider the Rosetta Stone to be one of the most important archaeological discoveries ever made. ________, the stone provided the key to deciphering Egyptian hieroglyphics, a writing system that had been unreadable for over a thousand years.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'After all' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Meanwhile' }, { letter: 'D', text: 'Alternatively' }], correct: 'A', explanation: '"After all" provides the justification for why the Rosetta Stone is considered so important.' },
  { id: 'sat_rw_b8_069', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The study found that students who ate breakfast performed significantly better on standardized tests. ________, students who skipped breakfast showed lower concentration levels throughout the morning.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Conversely' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'Therefore' }, { letter: 'D', text: 'In addition' }], correct: 'A', explanation: '"Conversely" introduces the contrasting finding about students who skipped breakfast.' },
  { id: 'sat_rw_b8_070', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'medium', passage: 'A food critic writes: "The restaurant\'s signature dish—a deconstructed beef Wellington—arrives at the table looking like an abstract painting. Layers of flaky pastry, seared tenderloin, and earthy mushroom duxelles create a symphony of textures that would make even the most skeptical diner a convert."', question: 'The critic\'s use of figurative language primarily serves to:', options: [{ letter: 'A', text: 'convey the sensory richness and artistic quality of the dish' }, { letter: 'B', text: 'argue that the dish is overpriced for its portion size' }, { letter: 'C', text: 'criticize the restaurant for prioritizing appearance over taste' }, { letter: 'D', text: 'compare the restaurant unfavorably to its competitors' }], correct: 'A', explanation: 'Comparing the dish to a painting and a symphony emphasizes its artistic and sensory appeal.' },
  { id: 'sat_rw_b8_071', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The archaeological team uncovered pottery fragments dating back three thousand years. ________, these fragments suggest that a sophisticated civilization once thrived in the region.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Taken together' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Meanwhile' }, { letter: 'D', text: 'Alternatively' }], correct: 'A', explanation: '"Taken together" indicates that the fragments collectively support the conclusion about a past civilization.' },
  { id: 'sat_rw_b8_072', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The students were asked to choose between studying abroad in Paris ________ completing an internship in New York.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'and' }, { letter: 'B', text: 'or' }, { letter: 'C', text: 'but' }, { letter: 'D', text: 'nor' }], correct: 'A', explanation: '"Between...and" is the correct correlative pair in Standard English.' },
  { id: 'sat_rw_b8_073', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'Coral reefs support roughly twenty-five percent of all marine species. ________, they protect coastlines from storm damage by absorbing wave energy.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Beyond that' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Nonetheless' }, { letter: 'D', text: 'Instead' }], correct: 'A', explanation: '"Beyond that" adds a second important function of coral reefs to the first.' },
  { id: 'sat_rw_b8_074', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The diplomat\'s ________ response to the provocative question avoided escalating tensions, carefully acknowledging both sides without committing to either position.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'measured' }, { letter: 'B', text: 'inflammatory' }, { letter: 'C', text: 'dismissive' }, { letter: 'D', text: 'impetuous' }], correct: 'A', explanation: '"Measured" means carefully considered, matching the description of a careful, balanced response.' },
  { id: 'sat_rw_b8_075', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The software update was supposed to fix several known bugs. ________, it introduced new problems that caused the application to crash unexpectedly.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Unfortunately' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'Consequently' }, { letter: 'D', text: 'In other words' }], correct: 'A', explanation: '"Unfortunately" introduces an unexpected negative outcome that contradicted the update\'s purpose.' },
  { id: 'sat_rw_b8_076', category: 'writing', subcategory: 'sentence-structure', difficulty: 'medium', passage: 'The river flooded its banks after three days of continuous rain. Hundreds of residents were forced to evacuate their homes. Emergency shelters were set up at local schools.', question: 'Which choice best combines the second and third sentences?', options: [{ letter: 'A', text: 'Hundreds of residents were forced to evacuate their homes to emergency shelters set up at local schools.' }, { letter: 'B', text: 'Hundreds of residents evacuated, emergency shelters were set up at schools.' }, { letter: 'C', text: 'Evacuating their homes, emergency shelters at local schools were set up for hundreds of residents.' }, { letter: 'D', text: 'Hundreds of residents were forced to evacuate and shelters were set up and they were at schools.' }], correct: 'A', explanation: 'Option A smoothly connects the evacuation to the shelters in a single, clear sentence.' },
  { id: 'sat_rw_b8_077', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The company prides itself on innovation. ________, it allocates fifteen percent of its annual revenue to research and development.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'To that end' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Nonetheless' }, { letter: 'D', text: 'Conversely' }], correct: 'A', explanation: '"To that end" shows that the R&D spending is a deliberate action to support the goal of innovation.' },
  { id: 'sat_rw_b8_078', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'medium', passage: 'A historian writes: "We must be cautious about judging historical figures by modern standards. The moral frameworks of past centuries were fundamentally different from our own, and applying contemporary values retroactively risks distorting our understanding of history."', question: 'The historian\'s primary purpose is to:', options: [{ letter: 'A', text: 'argue for historical contextualization when evaluating past figures' }, { letter: 'B', text: 'defend the immoral actions of historical leaders' }, { letter: 'C', text: 'suggest that modern morality is inferior to past values' }, { letter: 'D', text: 'encourage readers to abandon all moral judgments about history' }], correct: 'A', explanation: 'The historian advocates understanding historical figures within their own time\'s moral framework.' },
  { id: 'sat_rw_b8_079', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The artist spent years developing her unique style, blending elements of cubism and surrealism. ________, her work defies easy categorization, which is precisely what makes it so compelling to critics.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'As such' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Meanwhile' }, { letter: 'D', text: 'Alternatively' }], correct: 'A', explanation: '"As such" connects the blended style to the logical result of defying categorization.' },
  { id: 'sat_rw_b8_080', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The hikers packed extra water, sunscreen, and snacks; ________ wanted to be prepared for the long trail ahead.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'they' }, { letter: 'B', text: 'them' }, { letter: 'C', text: 'those' }, { letter: 'D', text: 'it' }], correct: 'A', explanation: '"They" is the subject pronoun correctly referring to the plural "hikers."' },
  { id: 'sat_rw_b8_081', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The school district decided to eliminate single-use plastics from all cafeterias. ________, biodegradable utensils and reusable trays replaced plastic forks and Styrofoam containers.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Subsequently' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Nevertheless' }, { letter: 'D', text: 'On the other hand' }], correct: 'A', explanation: '"Subsequently" indicates that the replacement of items followed the decision chronologically.' },
  { id: 'sat_rw_b8_082', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Unlike traditional paper maps, GPS navigation systems provide real-time traffic updates and can reroute drivers around congestion. However, critics argue that over-reliance on GPS has diminished people\'s ability to navigate independently, making them vulnerable when technology fails.', question: 'The passage presents GPS navigation as:', options: [{ letter: 'A', text: 'a useful tool that nevertheless carries potential drawbacks' }, { letter: 'B', text: 'a technology that is entirely superior to paper maps' }, { letter: 'C', text: 'an unreliable system that should be abandoned' }, { letter: 'D', text: 'a minor improvement over traditional navigation methods' }], correct: 'A', explanation: 'The passage acknowledges GPS benefits (real-time updates) while noting the drawback of reduced independent navigation skills.' },
  { id: 'sat_rw_b8_083', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'Many small businesses struggled during the economic downturn. ________, several local restaurants closed permanently, unable to sustain themselves without steady customer traffic.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'For instance' }, { letter: 'B', text: 'Conversely' }, { letter: 'C', text: 'Nonetheless' }, { letter: 'D', text: 'Instead' }], correct: 'A', explanation: '"For instance" provides a specific example of small businesses that struggled.' },
  { id: 'sat_rw_b8_084', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The author\'s latest novel takes a ________ approach to storytelling, weaving together multiple timelines and perspectives in a way that challenges readers to piece the narrative together themselves.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'nonlinear' }, { letter: 'B', text: 'conventional' }, { letter: 'C', text: 'simplistic' }, { letter: 'D', text: 'predictable' }], correct: 'A', explanation: '"Nonlinear" means not in a straight sequence, matching the description of multiple timelines.' },
  { id: 'sat_rw_b8_085', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The theory of plate tectonics explains how Earth\'s continents move over geological time. ________, it accounts for the occurrence of earthquakes and volcanic eruptions along plate boundaries.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Additionally' }, { letter: 'B', text: 'Nevertheless' }, { letter: 'C', text: 'Instead' }, { letter: 'D', text: 'Conversely' }], correct: 'A', explanation: '"Additionally" introduces another phenomenon explained by plate tectonics.' },
  { id: 'sat_rw_b8_086', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The candidate campaigned on a promise of lower taxes. ________, upon taking office, she proposed a budget that actually increased several tax rates.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Ironically' }, { letter: 'B', text: 'Accordingly' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'Furthermore' }], correct: 'A', explanation: '"Ironically" highlights the contradiction between the campaign promise and the actual policy.' },
  { id: 'sat_rw_b8_087', category: 'writing', subcategory: 'grammar', difficulty: 'medium', passage: 'The proposed legislation requires that every employee ________ a background check before starting work.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'undergo' }, { letter: 'B', text: 'undergoes' }, { letter: 'C', text: 'undergoing' }, { letter: 'D', text: 'has undergone' }], correct: 'A', explanation: 'The subjunctive mood is required after "requires that," so the base form "undergo" is correct.' },
  { id: 'sat_rw_b8_088', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'Sleep deprivation has been linked to impaired cognitive function, weakened immune response, and increased risk of chronic disease. ________, getting adequate sleep is one of the simplest ways to improve overall health.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'In light of this' }, { letter: 'B', text: 'On the contrary' }, { letter: 'C', text: 'Meanwhile' }, { letter: 'D', text: 'In contrast' }], correct: 'A', explanation: '"In light of this" draws a conclusion about the importance of sleep from the stated health risks.' },
  { id: 'sat_rw_b8_089', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'medium', passage: 'A climate scientist writes in a public editorial: "The data is unambiguous. Global average temperatures have risen by 1.1 degrees Celsius since pre-industrial times, and the rate of increase is accelerating. We cannot afford to treat this as a distant problem—the effects are here, and they are intensifying."', question: 'The scientist\'s tone in this passage is best described as:', options: [{ letter: 'A', text: 'urgent and evidence-based' }, { letter: 'B', text: 'detached and speculative' }, { letter: 'C', text: 'optimistic and encouraging' }, { letter: 'D', text: 'humorous and lighthearted' }], correct: 'A', explanation: 'The scientist cites specific data and uses emphatic language ("cannot afford," "intensifying") to convey urgency.' },
  { id: 'sat_rw_b8_090', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'medium', passage: 'The library\'s digital lending program has expanded access to books for rural communities. ________, residents who previously had to drive hours to reach the nearest library can now borrow e-books from home.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Now' }, { letter: 'B', text: 'However' }, { letter: 'C', text: 'In contrast' }, { letter: 'D', text: 'Instead' }], correct: 'A', explanation: '"Now" signals the current improved situation resulting from the digital lending program.' },
  { id: 'sat_rw_b8_091', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'The philosopher argued that moral truths are not discovered but constructed by societies over time. ________, what one culture considers ethical may be viewed as reprehensible by another, and neither perspective can claim absolute validity.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'By this reasoning' }, { letter: 'B', text: 'In addition' }, { letter: 'C', text: 'Surprisingly' }, { letter: 'D', text: 'Meanwhile' }], correct: 'A', explanation: '"By this reasoning" shows that the cultural variation logically follows from the philosopher\'s constructivist argument.' },
  { id: 'sat_rw_b8_092', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'hard', passage: 'An economist writes: "Proponents of universal basic income often cite its potential to reduce poverty and stimulate consumer spending. However, they tend to downplay the significant fiscal challenges of funding such a program. A truly honest debate requires acknowledging that UBI would necessitate either substantial tax increases or cuts to existing social programs—neither of which is politically painless."', question: 'The economist\'s primary rhetorical strategy is to:', options: [{ letter: 'A', text: 'challenge the completeness of UBI advocates\' arguments by raising overlooked fiscal realities' }, { letter: 'B', text: 'reject the concept of universal basic income as fundamentally flawed' }, { letter: 'C', text: 'endorse universal basic income while noting minor implementation challenges' }, { letter: 'D', text: 'compare universal basic income to other poverty reduction programs' }], correct: 'A', explanation: 'The economist does not reject UBI outright but argues that supporters omit important fiscal trade-offs.' },
  { id: 'sat_rw_b8_093', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'The novelist\'s early works were characterized by sparse, minimalist prose that relied on implication rather than explicit description. Her later novels, ________, embraced elaborate imagery and complex sentence structures, reflecting her evolving artistic vision.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'by contrast' }, { letter: 'B', text: 'similarly' }, { letter: 'C', text: 'in addition' }, { letter: 'D', text: 'consequently' }], correct: 'A', explanation: '"By contrast" highlights the shift from minimalist early works to elaborate later ones.' },
  { id: 'sat_rw_b8_094', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The board of directors, after reviewing the quarterly earnings reports and consulting with external auditors, ________ to restructure the company\'s debt obligations.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'voted' }, { letter: 'B', text: 'vote' }, { letter: 'C', text: 'voting' }, { letter: 'D', text: 'have voted' }], correct: 'A', explanation: '"Board" is a singular collective noun; the past tense "voted" agrees with it and fits the narrative context.' },
  { id: 'sat_rw_b8_095', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Some linguists argue that the Sapir-Whorf hypothesis—the idea that language shapes thought—overstates the influence of linguistic structures on cognition. While it is true that different languages categorize the world in different ways, research suggests that speakers of all languages can perceive and reason about concepts for which their language lacks specific terms. The relationship between language and thought, these scholars contend, is one of influence rather than determination.', question: 'The passage suggests that the scholars mentioned would most likely agree with which statement?', options: [{ letter: 'A', text: 'Language affects how people think but does not rigidly constrain their cognitive abilities.' }, { letter: 'B', text: 'The Sapir-Whorf hypothesis has been entirely disproven by modern research.' }, { letter: 'C', text: 'All languages categorize the world in fundamentally identical ways.' }, { letter: 'D', text: 'Language has no meaningful impact on human thought processes.' }], correct: 'A', explanation: 'The scholars argue for "influence rather than determination," meaning language affects but does not control thought.' },
  { id: 'sat_rw_b8_096', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'The quantum computing breakthrough has the potential to revolutionize cryptography, drug discovery, and climate modeling. ________, the technology remains in its infancy, with current quantum computers prone to errors and limited in the number of qubits they can sustain.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'At present, however' }, { letter: 'B', text: 'As a result' }, { letter: 'C', text: 'In other words' }, { letter: 'D', text: 'Moreover' }], correct: 'A', explanation: '"At present, however" contrasts the future potential with the current technological limitations.' },
  { id: 'sat_rw_b8_097', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'hard', passage: 'A literary critic writes: "To dismiss genre fiction as inherently inferior to literary fiction is to ignore the rich tradition of social commentary embedded in science fiction, the psychological depth found in the best mystery novels, and the cultural significance of romance narratives across centuries."', question: 'The critic structures the argument by:', options: [{ letter: 'A', text: 'providing specific counterexamples from multiple genres to challenge a broad generalization' }, { letter: 'B', text: 'using statistical data to prove genre fiction outsells literary fiction' }, { letter: 'C', text: 'quoting famous authors who have written in multiple genres' }, { letter: 'D', text: 'conceding that literary fiction is superior before defending genre fiction' }], correct: 'A', explanation: 'The critic counters the dismissal by citing virtues of science fiction, mystery, and romance respectively.' },
  { id: 'sat_rw_b8_098', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'The city\'s transportation plan prioritizes building new highways to alleviate congestion. Urban planning experts, ________, argue that expanding highways often induces additional demand, ultimately worsening the very problem they are intended to solve.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'on the other hand' }, { letter: 'B', text: 'consequently' }, { letter: 'C', text: 'similarly' }, { letter: 'D', text: 'to that end' }], correct: 'A', explanation: '"On the other hand" introduces the experts\' opposing view to the city\'s highway-building approach.' },
  { id: 'sat_rw_b8_099', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The researcher analyzed decades of temperature data. She identified a clear warming trend. Her findings were published in a leading scientific journal. The study prompted renewed calls for emission reductions.', question: 'Which choice most effectively combines these sentences?', options: [{ letter: 'A', text: 'After analyzing decades of temperature data and identifying a clear warming trend, the researcher published her findings in a leading scientific journal, prompting renewed calls for emission reductions.' }, { letter: 'B', text: 'The researcher analyzed temperature data, she identified a warming trend, her findings were published, and there were calls for emission reductions.' }, { letter: 'C', text: 'Analyzing data and identifying trends and publishing findings, emission reductions were called for.' }, { letter: 'D', text: 'The researcher analyzed decades of temperature data and identified a clear warming trend and published findings and prompted calls.' }], correct: 'A', explanation: 'Option A uses subordination and participial phrases to create a logical, flowing sentence.' },
  { id: 'sat_rw_b8_100', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The new policy was intended to be ________, applying equally to all employees regardless of their department or seniority, but critics noted that its practical effects disproportionately burdened junior staff.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'equitable' }, { letter: 'B', text: 'arbitrary' }, { letter: 'C', text: 'discriminatory' }, { letter: 'D', text: 'lenient' }], correct: 'A', explanation: '"Equitable" means fair and impartial, matching the intent of applying rules equally to everyone.' },
  { id: 'sat_rw_b8_101', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'The archaeological evidence suggests that the ancient settlement was abandoned gradually rather than destroyed by a single catastrophic event. ________, the absence of charred remains and the orderly pattern of discarded possessions indicate a planned departure over an extended period.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Specifically' }, { letter: 'B', text: 'Conversely' }, { letter: 'C', text: 'Meanwhile' }, { letter: 'D', text: 'Alternatively' }], correct: 'A', explanation: '"Specifically" introduces the precise evidence supporting the claim of gradual abandonment.' },
  { id: 'sat_rw_b8_102', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'hard', passage: 'A political commentator writes: "Those who oppose immigration reform often frame the issue in purely economic terms, arguing that immigrants take jobs from native-born workers. This framing conveniently ignores decades of research showing that immigration generates net positive economic effects and overlooks the humanitarian dimensions of the debate entirely."', question: 'The commentator\'s argument is best characterized as:', options: [{ letter: 'A', text: 'a critique of how opponents selectively frame the immigration debate' }, { letter: 'B', text: 'a neutral summary of both sides of the immigration issue' }, { letter: 'C', text: 'an emotional appeal for open borders without restrictions' }, { letter: 'D', text: 'a concession that immigration has negative economic effects' }], correct: 'A', explanation: 'The commentator criticizes opponents for using a narrow economic frame that ignores research and humanitarian concerns.' },
  { id: 'sat_rw_b8_103', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The study revealed that participants who ________ regularly for at least six months showed significant improvements in both memory retention and problem-solving ability.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'had exercised' }, { letter: 'B', text: 'has exercised' }, { letter: 'C', text: 'exercising' }, { letter: 'D', text: 'exercises' }], correct: 'A', explanation: '"Had exercised" is the past perfect tense, indicating the exercise occurred before the study revealed results.' },
  { id: 'sat_rw_b8_104', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'While desalination technology offers a potential solution to freshwater scarcity, it remains prohibitively expensive for many developing nations. ________, the process generates concentrated brine that, if improperly disposed of, can devastate marine ecosystems.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Compounding this concern' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Consequently' }, { letter: 'D', text: 'On the positive side' }], correct: 'A', explanation: '"Compounding this concern" introduces an additional problem layered on top of the cost issue.' },
  { id: 'sat_rw_b8_105', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The concept of "herd immunity" relies on a critical threshold of vaccinated individuals within a population. When this threshold is reached, even unvaccinated individuals receive indirect protection because the pathogen cannot spread efficiently. However, if vaccination rates drop below the threshold, the entire community—including those who cannot be vaccinated for medical reasons—becomes vulnerable to outbreaks.', question: 'The passage implies that herd immunity is best understood as:', options: [{ letter: 'A', text: 'a collective benefit that depends on widespread individual participation in vaccination' }, { letter: 'B', text: 'a guarantee that unvaccinated individuals will never contract diseases' }, { letter: 'C', text: 'a concept that applies only to individuals with medical exemptions' }, { letter: 'D', text: 'an outdated theory that modern science has largely discredited' }], correct: 'A', explanation: 'The passage emphasizes that herd immunity requires a critical mass of vaccinated people to protect the whole community.' },
  { id: 'sat_rw_b8_106', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'The memoir avoids the self-congratulatory tone common to many political autobiographies. ________, the author reflects candidly on her failures and misjudgments, offering readers a more nuanced portrait of public life.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Instead' }, { letter: 'B', text: 'Similarly' }, { letter: 'C', text: 'As a result' }, { letter: 'D', text: 'In addition' }], correct: 'A', explanation: '"Instead" contrasts the expected self-congratulatory tone with the author\'s actual candid approach.' },
  { id: 'sat_rw_b8_107', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The researcher\'s hypothesis was ultimately ________ by the experimental results: every trial produced outcomes that directly contradicted her predictions.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'refuted' }, { letter: 'B', text: 'corroborated' }, { letter: 'C', text: 'validated' }, { letter: 'D', text: 'bolstered' }], correct: 'A', explanation: '"Refuted" means disproven, matching the context of results that contradicted the hypothesis.' },
  { id: 'sat_rw_b8_108', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'Critics of standardized testing argue that such assessments measure test-taking ability rather than genuine understanding. ________, they point to studies showing that intensive test preparation can significantly boost scores without improving actual subject knowledge.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'To support this claim' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'On the other hand' }, { letter: 'D', text: 'Regardless' }], correct: 'A', explanation: '"To support this claim" introduces evidence that backs up the critics\' argument.' },
  { id: 'sat_rw_b8_109', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'The orchestra\'s performance of the symphony, which featured intricate harmonies and demanding tempo changes, ________ the audience to their feet for a standing ovation.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'brought' }, { letter: 'B', text: 'bring' }, { letter: 'C', text: 'bringing' }, { letter: 'D', text: 'have brought' }], correct: 'A', explanation: '"Brought" is the past tense verb agreeing with the singular subject "performance."' },
  { id: 'sat_rw_b8_110', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'hard', passage: 'A technology executive writes: "People worry that artificial intelligence will eliminate millions of jobs. But history tells us a different story. Every major technological revolution—from the printing press to the internet—has created far more jobs than it destroyed. The key is not to resist innovation but to invest in education and retraining programs that help workers adapt."', question: 'The executive\'s argument relies primarily on:', options: [{ letter: 'A', text: 'drawing a historical analogy to counter fears about AI\'s impact on employment' }, { letter: 'B', text: 'presenting original research data on AI job displacement' }, { letter: 'C', text: 'appealing to readers\' emotions through personal anecdotes' }, { letter: 'D', text: 'conceding that AI will inevitably destroy more jobs than it creates' }], correct: 'A', explanation: 'The executive uses past technological revolutions as analogies to argue AI will follow the same pattern.' },
  { id: 'sat_rw_b8_111', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'The anthropologist\'s fieldwork revealed that the community\'s oral traditions served not merely as entertainment but as a mechanism for transmitting legal codes, historical records, and ecological knowledge across generations. ________, the loss of these traditions threatens far more than cultural heritage—it risks erasing centuries of accumulated practical wisdom.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Consequently' }, { letter: 'B', text: 'In contrast' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'Incidentally' }], correct: 'A', explanation: '"Consequently" shows that the threat of lost wisdom follows logically from the traditions\' multifaceted importance.' },
  { id: 'sat_rw_b8_112', category: 'writing', subcategory: 'sentence-structure', difficulty: 'hard', passage: 'The treaty was signed by both nations. It aimed to reduce nuclear arsenals. Implementation was to occur over a ten-year period. Independent inspectors would verify compliance.', question: 'Which choice most effectively combines these sentences?', options: [{ letter: 'A', text: 'Signed by both nations, the treaty aimed to reduce nuclear arsenals over a ten-year period, with independent inspectors verifying compliance.' }, { letter: 'B', text: 'The treaty was signed by both nations and it aimed to reduce nuclear arsenals and implementation was over ten years and inspectors would verify.' }, { letter: 'C', text: 'Both nations signed the treaty, reducing arsenals, implemented over ten years, verified by inspectors.' }, { letter: 'D', text: 'Signed by both nations, the treaty aimed to reduce arsenals, implementation over ten years, compliance verified.' }], correct: 'A', explanation: 'Option A uses participial phrases and prepositional phrases to combine all four ideas fluently.' },
  { id: 'sat_rw_b8_113', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The senator\'s speech was deliberately ________, avoiding specific commitments while using broad, feel-good language that could appeal to voters across the political spectrum.', question: 'Which word best completes the text?', options: [{ letter: 'A', text: 'vague' }, { letter: 'B', text: 'forthright' }, { letter: 'C', text: 'incendiary' }, { letter: 'D', text: 'precise' }], correct: 'A', explanation: '"Vague" means lacking specific detail, matching the description of avoiding commitments and using broad language.' },
  { id: 'sat_rw_b8_114', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'Proponents of year-round schooling argue that extended breaks cause students to lose academic gains, a phenomenon known as "summer slide." Opponents counter that children need unstructured time for creative play, family bonding, and rest. ________, the debate reflects a deeper tension between academic rigor and holistic child development.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Ultimately' }, { letter: 'B', text: 'For example' }, { letter: 'C', text: 'In addition' }, { letter: 'D', text: 'Meanwhile' }], correct: 'A', explanation: '"Ultimately" signals a broader conclusion that synthesizes the two competing perspectives.' },
  { id: 'sat_rw_b8_115', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'hard', passage: 'An environmental activist writes: "We stand at a crossroads. One path leads to continued extraction, rising temperatures, and ecological collapse. The other demands sacrifice and innovation but offers our children a livable planet. The choice should not be difficult, yet powerful interests continue to steer us toward destruction."', question: 'The activist\'s use of the "crossroads" metaphor primarily serves to:', options: [{ letter: 'A', text: 'frame the environmental debate as a decisive moment requiring immediate choice' }, { letter: 'B', text: 'suggest that environmental policy should focus on transportation infrastructure' }, { letter: 'C', text: 'acknowledge that both paths forward are equally viable' }, { letter: 'D', text: 'minimize the urgency of addressing climate change' }], correct: 'A', explanation: 'The crossroads metaphor presents two starkly different futures to compel readers to act now.' },
  { id: 'sat_rw_b8_116', category: 'writing', subcategory: 'grammar', difficulty: 'hard', passage: 'Neither the statistical analysis nor the qualitative interviews ________ a clear causal relationship between social media use and declining mental health in adolescents.', question: 'Which choice conforms to Standard English?', options: [{ letter: 'A', text: 'established' }, { letter: 'B', text: 'establishes' }, { letter: 'C', text: 'establishing' }, { letter: 'D', text: 'has established' }], correct: 'A', explanation: 'With "neither...nor," the verb agrees with the nearer plural subject "interviews" and uses past tense "established."' },
  { id: 'sat_rw_b8_117', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'The restoration of the Renaissance painting took over five years and cost nearly two million dollars. ________, the result justified the investment: layers of grime and previous overpainting were removed to reveal the artist\'s original vibrant colors for the first time in centuries.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'In the end' }, { letter: 'B', text: 'Meanwhile' }, { letter: 'C', text: 'Conversely' }, { letter: 'D', text: 'In addition' }], correct: 'A', explanation: '"In the end" signals that, after the lengthy and costly process, the outcome was worthwhile.' },
  { id: 'sat_rw_b8_118', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Economists have long debated whether minimum wage increases lead to job losses. Classical economic theory predicts that raising the price floor on labor should reduce demand for workers. However, several landmark empirical studies—most notably Card and Krueger\'s analysis of fast-food restaurants—found no significant negative employment effects following moderate minimum wage increases. These findings suggest that the labor market is more complex than simple supply-and-demand models predict.', question: 'The passage characterizes the relationship between economic theory and empirical research on minimum wage as one in which:', options: [{ letter: 'A', text: 'real-world data has complicated the predictions of classical models' }, { letter: 'B', text: 'theory and data are in complete agreement about minimum wage effects' }, { letter: 'C', text: 'empirical studies have conclusively proven that minimum wage has no effect on employment' }, { letter: 'D', text: 'classical theory has been universally abandoned by modern economists' }], correct: 'A', explanation: 'The passage presents empirical findings that challenge but do not completely overturn classical predictions.' },
  { id: 'sat_rw_b8_119', category: 'writing', subcategory: 'expression-of-ideas', difficulty: 'hard', passage: 'The philosopher contended that free will is an illusion, arguing that every human decision is the inevitable product of prior causes stretching back to the beginning of time. ________, she acknowledged that society must continue to operate as if individuals bear responsibility for their actions, since the alternative—abandoning all notions of accountability—would be catastrophic.', question: 'Which transition best completes the text?', options: [{ letter: 'A', text: 'Nonetheless' }, { letter: 'B', text: 'Therefore' }, { letter: 'C', text: 'Similarly' }, { letter: 'D', text: 'In other words' }], correct: 'A', explanation: '"Nonetheless" introduces the philosopher\'s pragmatic concession that contradicts her theoretical position on free will.' },
  { id: 'sat_rw_b8_120', category: 'reading', subcategory: 'rhetorical-analysis', difficulty: 'hard', passage: 'A museum curator writes: "The impulse to repatriate cultural artifacts to their countries of origin is understandable and, in many cases, morally compelling. Yet we must also consider that some objects have been preserved precisely because they were housed in institutions with the resources to protect them. A blanket policy of repatriation, without attention to the specific circumstances of each artifact, risks replacing one injustice with another."', question: 'The curator\'s argument is best described as:', options: [{ letter: 'A', text: 'a nuanced position that supports repatriation in principle while cautioning against a one-size-fits-all approach' }, { letter: 'B', text: 'an unqualified defense of keeping all cultural artifacts in Western museums' }, { letter: 'C', text: 'a passionate demand for the immediate return of all artifacts' }, { letter: 'D', text: 'a dismissal of repatriation as unnecessary and impractical' }], correct: 'A', explanation: 'The curator acknowledges the moral case for repatriation but argues for case-by-case consideration rather than blanket policy.' },
];
